import axios from "axios";
import { parseStringPromise } from "xml2js";

// Import bookmarks from a remote XML feed. Previously used the deprecated
// `request` library (unmaintained, no fixed version for its known
// vulnerabilities); replaced with axios, which the rest of the app already
// uses for outbound HTTP.
export async function fetchXml(url) {
  const res = await axios.get(url, {
    validateStatus: () => true,
    responseType: "text",
  });
  if (res.status >= 400) {
    throw new Error(`upstream ${res.status}`);
  }
  return res.data;
}

